+        var a = (r1 * r1 - r2 * r2 + d * d) / (2 * d),
+            h = Math.sqrt(r1 * r1 - a * a),
+            x0 = p1.x + a * (p2.x - p1.x) / d,
+            y0 = p1.y + a * (p2.y - p1.y) / d,
+            rx = -(p2.y - p1.y) * (h / d),
+            ry = -(p2.x - p1.x) * (h / d);
