+                { x: x0 - rx, y : y0 + ry }];
+    };
+
+    /** Returns the center of a bunch of points */
+    venn.getCenter = function(points) {
+        var center = { x: 0, y: 0};
+        for (var i =0; i < points.length; ++i ) {
+            center.x += points[i].x;
+            center.y += points[i].y;
+        }
+        center.x /= points.length;
+        center.y /= points.length;
+        return center;
+    };
+})(venn);
