+                    .attrTween("d", pathTween);
+
+                var updateText = update.select("text")
+                    .text(function (d) { return label(d); } )
+                    .each("end", venn.wrapText(circles, label))
+                    .attr("x", function(d) {
+                        return Math.floor(textCentres[d.sets].x);
+                    })
+                    .attr("y", function(d) {
+                        return Math.floor(textCentres[d.sets].y);
+                    });
