+<!doctype html>
+<html lang="en">
+<head>
+    <meta charset="utf-8">
+    <title>Intersection Tooltip venn.js example</title>
+</head>
+
+<body>
+    <div class="venn"></div>
+</body>
+
+<style>
+.venntooltip {
+  position: absolute;
+  text-align: center;
+  width: 128px;
+  height: 18px;
+  background: #333;
+  color: #ddd;
+  border: 0px;
+  border-radius: 8px;
+  opacity: 0;
+}
+</style>
+
+<script src="http://d3js.org/d3.v2.min.js"></script>
+<script src="../venn.js"></script>
+<script src="./lastfm.jsonp"></script>
+<script>
+// get positions for each set
+sets = venn.venn(sets, overlaps);
+
+// draw the diagram in the 'venn' div
+var diagram = venn.drawD3Diagram(d3.select(".venn"), sets, 500, 500);
+
+// add a tooltip showing the size of each set/intersection
+var tooltip = d3.select("body").append("div")
+    .attr("class", "venntooltip");
+
+d3.selection.prototype.moveParentToFront = function() {
+  return this.each(function(){
+    this.parentNode.parentNode.appendChild(this.parentNode);
+  });
+};
+
+// hover on all the circles
+diagram.circles
+    .style("stroke-opacity", 0)
+    .style("stroke", "white")
+    .style("stroke-width", "2")
+    .on("mousemove", function() {
+        tooltip.style("left", (d3.event.pageX) + "px")
+               .style("top", (d3.event.pageY - 28) + "px");
+    })
+    .on("mouseover", function(d, i) {
+        var selection = d3.select(this);
